SELECT sc.*, s.name as student_name, s.student_no, c.class_name, sub.subject_name
FROM score_info sc
LEFT JOIN student_info s ON sc.student_id = s.id
LEFT JOIN class_info c ON s.class_id = c.id
LEFT JOIN subject sub ON sc.subject_id = sub.id
WHERE 1=1 AND sc.status = 1

    AND sc.student_id = #{studentId}


    AND s.class_id = #{classId}


    AND sc.subject_id = #{subjectId}


    AND sc.subject_id IN

        #{sid}



    AND sc.score >= #{minScore}


    AND sc.score <= #{maxScore}

ORDER BY sc.exam_date DESC, sc.create_time DESC

SELECT sc.*, s.name as student_name, s.student_no, c.class_name, sub.subject_name, (SELECT SUM(score) FROM score_info WHERE student_id = sc.student_id AND status = 1) as total_score FROM score_info sc LEFT JOIN student_info s ON sc.student_id = s.id LEFT JOIN class_info c ON s.class_id = c.id LEFT JOIN subject sub ON sc.subject_id = sub.id WHERE 1=1 AND sc.status = 1
AND s.class_id = #{classId}
AND sc.subject_id IN
#{sid}
ORDER BY total_score DESC
